use std::io::{self, BufRead, BufReader};

struct ConfigData {
    lines: Vec<String>,
}

fn process_inputs(reader: impl BufRead) -> io::Result<ConfigData> {
    let reader = BufReader::new(reader);
    let mut lines_vec = Vec::new();
    for line in reader.lines() {
        match line {
            Ok(l) => lines_vec.push(l),
            Err(e) => return Err(e),
        }
    }
    Ok(ConfigData { lines: lines_vec })
}

fn main() -> io::Result<()> {
    let stdin = io::stdin();
    let result = process_inputs(stdin.lock())?;

    println!("Successfully read {} lines from standard input.", result.lines.len());

    if !result.lines.is_empty() {
        println!("First line processed: {}", &result.lines[0]);
    }

    Ok(())
}
